// Generated by GitHub Copilot
import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';

const CHECKOUT_STORAGE_KEY = 'tienda_react_checkout_form';

/**
 * Reads persisted checkout form values safely.
 * @returns {{ name: string, email: string, address: string, city: string, zip: string, card: string }}
 */
function getInitialCheckoutForm() {
  const fallback = {
    name: '',
    email: '',
    address: '',
    city: '',
    zip: '',
    card: '',
  };

  try {
    const rawForm = localStorage.getItem(CHECKOUT_STORAGE_KEY);
    return rawForm ? { ...fallback, ...JSON.parse(rawForm) } : fallback;
  } catch {
    return fallback;
  }
}

/**
 * Checkout page with a simple order form.
 * On submission it clears the cart and redirects to a confirmation page.
 * Input validation happens on the client boundary.
 */
export default function Checkout() {
  const { cart, totalPrice, dispatch, showToast } = useCart();
  const navigate = useNavigate();

  const [form, setForm] = useState(getInitialCheckoutForm);
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    localStorage.setItem(CHECKOUT_STORAGE_KEY, JSON.stringify(form));
  }, [form]);

  const validate = () => {
    const newErrors = {};
    if (!form.name.trim()) newErrors.name = 'El nombre es obligatorio.';
    if (!form.email.trim() || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      newErrors.email = 'Ingresa un correo válido.';
    }
    if (!form.address.trim()) newErrors.address = 'La dirección es obligatoria.';
    if (!form.city.trim()) newErrors.city = 'La ciudad es obligatoria.';
    if (!form.zip.trim() || !/^\d{4,10}$/.test(form.zip)) {
      newErrors.zip = 'Código postal inválido (4-10 dígitos).';
    }
    if (!form.card.trim() || !/^\d{16}$/.test(form.card.replace(/\s/g, ''))) {
      newErrors.card = 'Número de tarjeta inválido (16 dígitos).';
    }
    return newErrors;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    const nextValue = name === 'card' ? value.replace(/[^\d\s]/g, '') : value;
    setForm((prev) => ({ ...prev, [name]: nextValue }));
    if (errors[name]) setErrors((prev) => ({ ...prev, [name]: undefined }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }
    setSubmitted(true);
    dispatch({ type: 'CLEAR_CART' });
    localStorage.removeItem(CHECKOUT_STORAGE_KEY);
    showToast('Pedido confirmado correctamente', 'success');
    setTimeout(() => navigate('/'), 3000);
  };

  if (cart.length === 0 && !submitted) {
    return (
      <main className="max-w-xl mx-auto px-4 py-16 text-center">
        <p className="text-5xl mb-4" aria-hidden="true">🛒</p>
        <h1 className="text-2xl font-bold text-gray-800 mb-2">No hay productos en el carrito</h1>
        <Link to="/" className="text-indigo-600 underline">Volver a la tienda</Link>
      </main>
    );
  }

  if (submitted) {
    return (
      <main className="max-w-xl mx-auto px-4 py-20 text-center" role="status" aria-live="polite">
        <p className="text-6xl mb-4" aria-hidden="true">✅</p>
        <h1 className="text-2xl font-bold text-gray-800 mb-2">¡Pedido confirmado!</h1>
        <p className="text-gray-500">Gracias por tu compra. Serás redirigido en unos segundos...</p>
      </main>
    );
  }

  const Field = ({ id, label, type = 'text', name, placeholder, autoComplete }) => (
    <div className="flex flex-col gap-1">
      <label htmlFor={id} className="text-sm font-medium text-gray-700">
        {label}
      </label>
      <input
        id={id}
        type={type}
        name={name}
        value={form[name]}
        onChange={handleChange}
        placeholder={placeholder}
        autoComplete={autoComplete}
        className={`border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition ${
          errors[name] ? 'border-red-400' : 'border-gray-300'
        }`}
        aria-invalid={!!errors[name]}
        aria-describedby={errors[name] ? `${id}-error` : undefined}
      />
      {errors[name] && (
        <span id={`${id}-error`} className="text-red-500 text-xs" role="alert">
          {errors[name]}
        </span>
      )}
    </div>
  );

  return (
    <main className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-gray-900 mb-8">Finalizar compra</h1>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Form */}
        <section className="flex-1" aria-label="Formulario de envío y pago">
          <form onSubmit={handleSubmit} noValidate className="flex flex-col gap-5">
            <fieldset className="flex flex-col gap-4">
              <legend className="font-semibold text-gray-800 text-base mb-1">Datos personales</legend>
              <Field id="name" label="Nombre completo" name="name" placeholder="Ana García" autoComplete="name" />
              <Field id="email" label="Correo electrónico" name="email" type="email" placeholder="ana@correo.com" autoComplete="email" />
            </fieldset>

            <fieldset className="flex flex-col gap-4">
              <legend className="font-semibold text-gray-800 text-base mb-1">Dirección de envío</legend>
              <Field id="address" label="Calle y número" name="address" placeholder="Av. Libertad 1234" autoComplete="street-address" />
              <div className="grid grid-cols-2 gap-4">
                <Field id="city" label="Ciudad" name="city" placeholder="Buenos Aires" autoComplete="address-level2" />
                <Field id="zip" label="Código postal" name="zip" placeholder="1425" autoComplete="postal-code" />
              </div>
            </fieldset>

            <fieldset className="flex flex-col gap-4">
              <legend className="font-semibold text-gray-800 text-base mb-1">Pago</legend>
              <Field id="card" label="Número de tarjeta" name="card" placeholder="1234 5678 9012 3456" autoComplete="cc-number" />
            </fieldset>

            <button
              type="submit"
              className="mt-2 bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white font-semibold px-4 py-3 rounded-xl transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
            >
              Confirmar pedido — ${totalPrice.toFixed(2)}
            </button>
          </form>
        </section>

        {/* Order summary */}
        <aside className="lg:w-72" aria-label="Resumen del pedido">
          <div className="bg-white rounded-2xl shadow p-6 sticky top-24">
            <h2 className="font-bold text-gray-800 text-base mb-4">Tu pedido</h2>
            <ul className="flex flex-col gap-3 mb-4" role="list">
              {cart.map((item) => (
                <li key={item.id} className="flex items-center gap-3">
                  <img
                    src={item.image}
                    alt={item.name}
                    className="w-12 h-12 rounded-lg object-cover flex-shrink-0"
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">{item.name}</p>
                    <p className="text-xs text-gray-500">x{item.quantity}</p>
                  </div>
                  <span className="text-sm font-semibold text-gray-900">
                    ${(item.price * item.quantity).toFixed(2)}
                  </span>
                </li>
              ))}
            </ul>
            <div className="border-t pt-3 flex justify-between font-bold text-gray-900">
              <span>Total</span>
              <span>${totalPrice.toFixed(2)}</span>
            </div>
          </div>
        </aside>
      </div>
    </main>
  );
}
